local LxBaseHandler = require("LApp.handler.LxBaseHandler")
---@class LxMailHandler:LxBaseHandler
local LxMailHandler = classX("LxMailHandler", LxBaseHandler)

function LxMailHandler:Initialize()
    LxBaseHandler.Initialize(self)
end

function LxMailHandler:Dispose()
    LxBaseHandler.Dispose(self)
end

function LxMailHandler:ClearHandler()
    LxBaseHandler.ClearHandler(self)
end

function LxMailHandler:InitOk()
end
-- 完成登录后
function LxMailHandler:LoginOk()
    self:MailListReq()
end

function LxMailHandler:InitHandler()
    self:AddMsgHandler(LxProtoIds.MailListResp, self.OnMailListResp, self)
    self:AddMsgHandler(LxProtoIds.MailAddResp, self.OnMailAddResp, self)
    self:AddMsgHandler(LxProtoIds.MailReceiveResp, self.OnMailReceiveResp, self)
    self:AddMsgHandler(LxProtoIds.MailReadResp, self.OnMailReadResp, self)
    self:AddMsgHandler(LxProtoIds.MailRemoveResp, self.OnMailRemoveResp, self)
    self:AddMsgHandler(LxProtoIds.MailSaveResp, self.OnMailSaveResp, self)
    self:AddMsgHandler(LxProtoIds.MailFollowResp, self.OnMailFollowResp, self)
    self:AddMsgHandler(LxProtoIds.MailDeleteResp, self.OnMailDeleteResp, self)
end

---@region s2c
function LxMailHandler:OnMailListResp(pb)
    ModuleCenter.Mail:SetMails(pb.mails)
    ModuleCenter.Mail:SetFollowRoleIds(pb.followRoleIds)
    FireEvent(EventNames.MAIL_LIST)
end
function LxMailHandler:OnMailAddResp(pb)
    local mails = pb.mails
    ModuleCenter.Mail:AddMails(mails)

end
function LxMailHandler:OnMailReceiveResp(pb)
    local receiveType = pb.receiveType
    local mailIds = pb.mailIds

    local thingsInfo = nil
    if pb:HasField("thingsInfo") then
        thingsInfo = pb.thingsInfo
    end
    CtrlCenter.Mail:OnMailReceive(receiveType, mailIds, thingsInfo)

end
function LxMailHandler:OnMailReadResp(pb)
    CtrlCenter.Mail:OnMailRead(pb.mailId)
end
function LxMailHandler:OnMailRemoveResp(pb)
    local rewardInfo = nil
    if pb:HasField("rewardInfo") then
        rewardInfo = pb.rewardInfo
    end
    CtrlCenter.Mail:OnMailRemove(pb.removeType, pb.mailIds, rewardInfo)
end
---@endregion s2c

---@region c2s
function LxMailHandler:MailListReq()
    local proto = LxProtoHelper.CreateProto(LxProtoIds.MailListReq)
    SendMessage(LxProtoIds.MailListReq, proto)
end

---@param receiveType number @领取方式,0-领取指定邮件附件,1-一键领取全部附件
---@param mailId number 邮件id 单个领取时传
---@param showType number 邮件展示类型 一键领取时传
function LxMailHandler:MailReceiveReq(receiveType, mailId, showType)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.MailReceiveReq)
    proto.receiveType = receiveType
    if receiveType == 0 then
        proto.mailId = mailId
    else
        proto.showType = showType
    end
    SendMessage(LxProtoIds.MailReceiveReq, proto)
end

function LxMailHandler:MailReadReq(mailId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.MailReadReq)
    proto.mailId = mailId
    SendMessage(LxProtoIds.MailReadReq, proto)
end
---@param removeType number@ 删除方式，0-删除指定邮件,1-删除全部
function LxMailHandler:MailRemoveReq(removeType , mailId, showType)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.MailRemoveReq)
    proto.removeType = removeType
    if removeType == 0 then
        proto.mailId = mailId
    else
        proto.showType = showType
    end
    SendMessage(LxProtoIds.MailRemoveReq, proto)
end
--- 邮件收藏（保存）请求
--- @param mailId number 邮件id
--- @param flag boolean 是否收藏标记，true收藏，false取消
function LxMailHandler:MailSaveReq(mailId, flag)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.MailSaveReq)
    proto.mailId = mailId
    proto.flag = flag
    SendMessage(LxProtoIds.MailSaveReq, proto)
end

--- 邮件收藏（保存）返回
function LxMailHandler:OnMailSaveResp(pb)
    ModuleCenter.Mail:SetSaveList(pb)
    FireEvent(EventNames.MAIL_SAVE)
    if pb.thingsInfo then
        FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.Mail, pb.thingsInfo)
    end
end
--- 邮件关注请求
--- @param mailId number 邮件id
--- @param flag boolean 是否收藏标记，true关注，false取消
function LxMailHandler:MailFollowReq(mailId, flag)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.MailFollowReq)
    proto.mailId = mailId
    proto.flag = flag
    SendMessage(LxProtoIds.MailFollowReq, proto)
end
--- 邮件关注（玩家）返回
function LxMailHandler:OnMailFollowResp(pb)
    ModuleCenter.Mail:SetFollowRoleId(pb)
    FireEvent(EventNames.MAIL_FOCUS)
end
function LxMailHandler:OnMailDeleteResp(pb)
    ModuleCenter.Mail:SetMailRemove(pb.mailIds)
    ShowSysMsg(I18nText(5617))
    FireEvent(EventNames.MAIL_REMOVE, pb.mailIds, pb.showType)
end
return LxMailHandler